var b="url",c="样式5：采购合同.html",d="generationDate",e=new Date(1781588649999.92),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="NewVariable",s="page",t="packageId",u="cc26a7091dd6455eb8b22e0f25a25016",v="type",w="Axure:Page",x="样式5：采购合同",y="notes",z="annotations",A="fn",B="1",C="ownerId",D="e3d3351e79e6426abc829abe7266b86a",E="label",F="扣款数量",G="说明",H="<p><span>1.若“入库数量”＜“采购数量”，给“追加数量”默认值</span></p><p><span>&nbsp; a.默认值= 采购数量-入库数量</span></p><p><span>&nbsp; b.应付金额也应该根据追加数量来计算</span></p><p><span>2.数字，保留两位</span></p><p><span><br></span></p>",I="2",J="5fea7ef9c22c4c7b8df9290647043896",K="追加数量",L="<p><span>1.若“入库数量”≥“采购数量”，给“追加数量”默认值</span></p><p><span>&nbsp; a.默认值= 入库数量-采购数量</span></p><p><span>&nbsp; b.应付金额也应该根据追加数量来计算</span></p><p><span>2.数字，保留两位</span></p>",M="3",N="316a9d19e115490da6b04a5abc6565cf",O="结算数量",P="<p><span>根据配置项进行计算及Toast提示：</span></p><p><span><br></span></p><p><span>配置项=0</span></p><p><span>1.结算数量=“</span><span style=\"color:#3399FF;\">采购数量</span><span>”+“追加数量”-“扣除数量”</span></p><p><span>2.Toast提示：</span><span style=\"font-family:'Microsoft YaHei ', 'Microsoft YaHei', sans-serif;\">结算数量=采购数量+追加数量-扣款数量</span></p><p><span style=\"font-family:'Microsoft YaHei ', 'Microsoft YaHei', sans-serif;\"><br></span></p><p><span>配置项=1</span></p><p><span>1.结算数量=“</span><span style=\"color:#3399FF;\">入库数量</span><span>”+“追加数量”-“扣除数量”</span></p><p><span>2.Toast提示：</span><span style=\"font-family:'Microsoft YaHei ', 'Microsoft YaHei', sans-serif;\">结算数量=</span><span>入库</span><span style=\"font-family:'Microsoft YaHei ', 'Microsoft YaHei', sans-serif;\">数量+追加数量-扣款数量</span></p><p><span><br></span></p>",Q="4",R="20b86234c9074d5bb8afb4db69eacaf7",S="应付金额",T="<p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">1.计算公式：应付金额=结算数量*含税单价+附加费</span></p><p><span style=\"font-family:'Nunito Sans', sans-serif;font-weight:400;\">2.Toast提示：应付金额=含税单价*结算数量+附加费</span></p>",U="5",V="f18c919b2981439f9c1c001ee989f58d",W="备注",X="<p><span>初始为空，可填写</span></p>",Y="6",Z="018883aba13447429d40e3e89ff7ecc8",ba=" 创建日期：2021-08-23 15:",bb="<p><span>精确到时分秒</span></p>",bc="7",bd="62a0372ccb69440c9e097209cd4256c9",be=" 审  核  人：李四，王五",bf="<p><span>采购付款申请到达至采购付款操作任务的审核人，若有多个审核人，用逗号进行拼接</span></p>",bg="8",bh="04f833ea6dec4274a4a706b23f68a6a6",bi="采购数量",bj="<p><span>本次付款数</span></p>",bk="9",bl="05e783715bd7405f9eb1812bc42f52ba",bm="附件说明",bn="<p><span>1.图片：缩略图，点击可放大</span></p><p><span>2.文档：点击下载</span></p>",bo="10",bp="221e5f71cde4497aaae7a9635929b382",bq="保存",br="<p><span>1.原型图带*号字段的必填校验，否则Toast提示：请填写XXX</span></p><p><span>2.根据配置项</span><span style=\"color:#02A7F0;\">system_config_COMPANY_TYPE</span><span>对“</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">收款账户</span><span>”字段校验是否非空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.配置项</span><span style=\"color:#02A7F0;\">==1</span><span>(汇隆) 时为</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:700;\">必填</span><span>字段；否则Toast提示：请选择收款账户</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; b.配置项==else 时无须校验</span></p><p><span>3.判断是否“要求付款金额”小于等于0（否则Toast提示“要求付款金额需大于0”）</span></p><p><span>4.判断[附加款项]部分是否存在单行金额为0或者空（否则Toast提示“要求付款金额需大于0”）</span></p>",bs="style",bt="baseStyle",bu="627587b6038d43cca051c114ac41ad32",bv="pageAlignment",bw="center",bx="fill",by="fillType",bz="solid",bA="color",bB=0xFFFFFFFF,bC="image",bD="imageAlignment",bE="near",bF="imageRepeat",bG="auto",bH="favicon",bI="sketchFactor",bJ="0",bK="colorStyle",bL="appliedColor",bM="fontName",bN="Applied Font",bO="borderWidth",bP="borderVisibility",bQ="borderFill",bR=0xFF797979,bS="cornerRadius",bT="cornerVisibility",bU="outerShadow",bV="on",bW=false,bX="offsetX",bY=5,bZ="offsetY",ca="blurRadius",cb="spread",cc="r",cd=0,ce="g",cf="b",cg="a",ch=0.349019607843137,ci="adaptiveStyles",cj="interactionMap",ck="diagram",c